import json
from azure.identity import DefaultAzureCredential
from azure.mgmt.resource import ResourceManagementClient
from azure.mgmt.resource.resources.v2022_09_01.models import (
    DeploymentWhatIf, DeploymentWhatIfProperties,
    DeploymentMode, WhatIfResultFormat
)

credential = DefaultAzureCredential()
client = ResourceManagementClient(credential, subscription_id)

with open('main.json') as f:
    template = json.load(f)

poller = client.deployments.begin_what_if(
    resource_group_name='myRG',
    deployment_name='whatif-check',
    parameters=DeploymentWhatIf(
        properties=DeploymentWhatIfProperties(
            mode=DeploymentMode.INCREMENTAL,
            template=template,
            what_if_settings={
                'resultFormat': WhatIfResultFormat.FULL_RESOURCE_PAYLOADS
            },
        )
    ),
)

result = poller.result()

for change in result.changes:
    print(f'{change.change_type.value:10} {change.resource_id}')
    if change.change_type.value == 'Modify':
        for delta in (change.delta or []):
            print(f'  {delta.path}: {delta.before} -> {delta.after}')

// main.bicep — typical resource group deployment
param location string = resourceGroup().location
param environment string
param appServicePlanSku string = environment == 'prod' ? 'P1v3' : 'B1'

resource plan 'Microsoft.Web/serverfarms@2023-01-01' = {
  name: 'asp-${environment}'
  location: location
  sku: {
    name: appServicePlanSku
  }
  kind: 'linux'
  properties: {
    reserved: true
  }
}

resource app 'Microsoft.Web/sites@2023-01-01' = {
  name: 'app-${environment}-${uniqueString(resourceGroup().id)}'
  location: location
  properties: {
    serverFarmId: plan.id
    httpsOnly: true
  }
}
